   221→    ReadBufferPtr read_buffer(new ReadBuffer());
   222→    write_buffer.SwapOut(read_buffer.get());
   223→    return read_buffer;
   224→}
   225→
   226→ReadBufferPtr HTTPRpcRequest::AssembleFailedResponse(
   227→        int32 error_code,
   228→        const std::string& reason,
   229→        std::string& err)
   230→{
   231→    std::ostringstream oss;
   232→    oss << "\"ERROR: " << error_code << ": "
   233→        << StringUtils::replace_all(reason, "\"", "\\\"") << "\"";
   234→
   235→    WriteBuffer write_buffer;
   236→    if (!RenderJsonResponse(&write_buffer, oss.str()))
   237→    {
   238→        err = "render json response failed";
   239→        return ReadBufferPtr();
   240→    }
   241→
   242→    ReadBufferPtr read_buffer(new ReadBuffer());
   243→    write_buffer.SwapOut(read_buffer.get());
   244→    return read_buffer;
   245→}
   246→
   247→bool HTTPRpcRequest::ParsePath()
   248→{
   249→    if (_path.empty() || _path[0] != '/')
   250→    {
   251→        return false;
   252→    }
   253→    // decode
   254→    _decoded_path = StringUtils::decode_url(_path,
   255→            (StringUtils::E_DECODE_RESERVED_CHAR | StringUtils::E_DECODE_PERCENT_SIGN_CHAR));
   256→#if defined( LOG )
   257→#else
   258→        SLOG(DEBUG, "ParsePath(): path=[%s], decoded_path=[%s]",
   259→                _path.c_str(), _decoded_path.c_str());
   260→#endif
   261→    // parse method
   262→    size_t start = 1; // skip first '/'
   263→    size_t end = _decoded_path.size();
   264→    for (size_t i = start; i != end; ++i)
   265→    {
   266→        if (_decoded_path[i] == '?' || _decoded_path[i] == '#')
   267→        {
   268→            end = i;
   269→            break;
   270→        }
   271→    }
   272→    _method = _decoded_path.substr(start, end - start);
   273→    // parse query
   274→    if (end < _decoded_path.size() && _decoded_path[end] == '?')
   275→    {
   276→        start = end + 1;
   277→        end = _decoded_path.size();
   278→        for (size_t i = start; i != end; ++i)
   279→        {
   280→            if (_decoded_path[i] == '#')
   281→            {
   282→                end = i;
   283→                break;
   284→            }
   285→        }
   286→        _query_string = _decoded_path.substr(start, end - start);
   287→        if (!_query_string.empty())
   288→        {
   289→            std::vector<std::string> param_list;
   290→            StringUtils::split(_query_string, "&", &param_list);
   291→            for (size_t i = 0; i < param_list.size(); ++i)
   292→            {
   293→                const std::string& param = param_list[i];
   294→                std::string::size_type pos = param.find('=');
   295→                if (pos != std::string::npos)
   296→                {
   297→                    std::string key = param.substr(0, pos);
   298→                    std::string value = param.substr(pos + 1);
   299→                    _query_params[key] = value;
   300→                }
   301→            }
   302→        }
   303→    }
   304→    // parse fragment
   305→    if (end < _decoded_path.size() && _decoded_path[end] == '#')
   306→    {
   307→        _fragment_id = _decoded_path.substr(end + 1);
   308→    }
   309→    return true;
   310→}
