   450→rapidjson::Document* HTTPRpcRequest::ParseJson(
   451→        const char* str,
   452→        std::string& err)
   453→{
   454→    rapidjson::Document* d = new rapidjson::Document();
   455→    d->Parse<0>(str);
   456→    if (d->HasParseError())
   457→    {
   458→        err = d->GetParseError();
   459→        delete d;
   460→        return NULL;
   461→    }
   462→    return d;
   463→}
